/// Memory usage tracker
#[derive(Debug)]
#[allow(dead_code)]
pub struct MemoryTracker {
    current_bytes: usize,
    max_bytes: usize,
}

#[allow(dead_code)]
impl MemoryTracker {
    pub fn new(max_bytes: usize) -> Self {
        Self {
            current_bytes: 0,
            max_bytes,
        }
    }

    pub fn allocate(&mut self, bytes: usize) -> bool {
        if self.current_bytes + bytes <= self.max_bytes {
            self.current_bytes += bytes;
            true
        } else {
            false
        }
    }

    pub fn release(&mut self, bytes: usize) {
        self.current_bytes = self.current_bytes.saturating_sub(bytes);
    }

    pub fn current(&self) -> usize {
        self.current_bytes
    }

    pub fn max(&self) -> usize {
        self.max_bytes
    }

    pub fn usage_percent(&self) -> f64 {
        (self.current_bytes as f64 / self.max_bytes as f64) * 100.0
    }
}

//! TPC-H Benchmark Comparison Tool
//!
//! Compares SQLRustGo performance against PostgreSQL and SQLite.
//!
//! # Usage
//!
//! ```bash
//! # Compare all systems
//! cargo run --example tpch_compare
//!
//! # Compare specific queries
//! cargo run --example tpch_compare -- --queries Q1,Q3,Q6
//!
//! # Save results to JSON
//! cargo run --example tpch_compare -- --output results.json
//! ```

use serde::{Deserialize, Serialize};
