}

fn create_tables(
    engine: &mut ExecutionEngine,
    lineitem_data: &[LineItemRow],
    orders_data: &[OrdersRow],
    customer_data: &[CustomerRow],
) {
    // Create lineitem table
    let _ = engine.execute(
        parse(
            "CREATE TABLE lineitem (
            l_orderkey INTEGER,
            l_partkey INTEGER,
            l_suppkey INTEGER,
            l_quantity REAL,
            l_extendedprice REAL,
            l_discount REAL,
            l_tax REAL,
            l_returnflag TEXT,
            l_shipdate INTEGER
        )",
        )
        .unwrap(),
    );

    // Create orders table
    let _ = engine.execute(
        parse(
            "CREATE TABLE orders (
            o_orderkey INTEGER,
            o_custkey INTEGER,
            o_orderstatus TEXT,
            o_orderpriority TEXT,
            o_totalprice INTEGER,
            o_orderdate INTEGER
        )",
        )
        .unwrap(),
    );

    // Create customer table
    let _ = engine.execute(
        parse(
            "CREATE TABLE customer (
            c_custkey INTEGER,
            c_name TEXT,
            c_nationkey INTEGER
        )",
        )
        .unwrap(),
    );

    // Insert data
    for row in lineitem_data {
        let sql = format!(
            "INSERT INTO lineitem VALUES ({}, {}, {}, {}, {}, {}, {}, '{}', {})",
            row.order_key,
            row.part_key,
            row.supp_key,
            row.quantity as i32,
            row.extended_price as i32,
            (row.discount * 100.0) as i32,
            (row.tax * 100.0) as i32,
            row.return_flag,
            row.ship_date
        );
        let _ = engine.execute(parse(&sql).unwrap());
    }

    for row in orders_data {
        let sql = format!(
            "INSERT INTO orders VALUES ({}, {}, '{}', '{}', {}, {})",
            row.order_key,
            row.cust_key,
            row.order_status,
            row.order_priority,
            row.total_price,
            row.order_date
        );
        let _ = engine.execute(parse(&sql).unwrap());
    }

    for row in customer_data {
        let sql = format!(
            "INSERT INTO customer VALUES ({}, '{}', {})",
            row.cust_key, row.name, row.nation_key
        );
        let _ = engine.execute(parse(&sql).unwrap());
    }
}

use clap::Parser;
use rand::Rng;
use std::fs::File;
use std::io::Write;
