}

/// Latency statistics in milliseconds
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LatencyStatsMs {
    /// 50th percentile in milliseconds
    pub p50_ms: f64,
    /// 95th percentile in milliseconds
    pub p95_ms: f64,
    /// 99th percentile in milliseconds
