mod tests {
    use super::*;

    #[test]
    fn test_latency_recorder() {
        let recorder = LatencyRecorder::new();

        for _ in 0..1000 {
            recorder.record(100);
        }

        let stats = recorder.snapshot();
        assert_eq!(stats.count, 1000);
        assert_eq!(stats.p50, 100);
    }

