use clap::Parser;
use sqlrustgo_bench::db::postgres_benchmark::PostgresBenchmark;
use std::fs;
use std::path::Path;
use tokio::runtime::Runtime;

mod cli;
mod commands;
mod metrics;
mod reporter;

use cli::BenchmarkConfig;
use commands::{custom, oltp, tpch};

#[derive(Parser, Debug)]
#[command(name = "benchmark")]
#[command(about = "SQLRustGo Benchmark CLI", long_about = None)]
struct Args {
    #[command(subcommand)]
    command: Command,
}

#[derive(Parser, Debug)]
enum Command {
    Tpch(cli::TpchArgs),
    Oltp(cli::OltpArgs),
    Custom(cli::CustomArgs),
}

/// Load configuration from file, CLI args take precedence
fn load_config(path: &str) -> Option<BenchmarkConfig> {
    let content = fs::read_to_string(path).ok()?;
    serde_json::from_str(&content).ok()
}

/// Run PostgreSQL comparison benchmark
fn run_pg_comparison(conn_str: &str, operations: u64) {
    let rt = Runtime::new().expect("Failed to create runtime");
    rt.block_on(async {
        let pg = PostgresBenchmark::new(conn_str);
        match pg.run_reads(operations).await {
            Ok(result) => {
                println!("\nPostgreSQL Results:");
                println!("  Total Time: {} ms", result.total_time_ms);
                println!("  QPS: {:.2}", result.qps);
                println!("  P50: {:.3} ms", result.latency_stats.p50_ms);
                println!("  P95: {:.3} ms", result.latency_stats.p95_ms);
                println!("  P99: {:.3} ms", result.latency_stats.p99_ms);
            }
            Err(e) => {
                eprintln!("PostgreSQL benchmark failed: {}", e);
            }
        }
    });
}

fn main() {
    let args = Args::parse();

    match args.command {
        Command::Tpch(tpch_args) => {
            // Load config file if provided
            let config = tpch_args.config.as_ref().and_then(|p| load_config(p));
            let output = tpch_args
                .output
                .clone()
                .or_else(|| config.as_ref().and_then(|c| c.output.clone()));
            let pg_conn = tpch_args
                .pg_conn
                .clone()
                .or_else(|| config.as_ref().and_then(|c| c.pg_conn.clone()));

            let result = tpch::run(tpch_args);
            if let Some(output_path) = output {
                result.save(Path::new(&output_path)).unwrap();
                println!("Results saved to: {}", output_path);
            } else {
                result.print_json();
            }

            // Run PostgreSQL comparison if connection provided
            if let Some(ref conn) = pg_conn {
                println!("\n=== PostgreSQL Comparison ===");
                run_pg_comparison(conn, 100);
            }
        }
        Command::Oltp(oltp_args) => {
            let config = oltp_args.config.as_ref().and_then(|p| load_config(p));
            let output = oltp_args
                .output
                .clone()
                .or_else(|| config.as_ref().and_then(|c| c.output.clone()));
            let pg_conn = oltp_args
                .pg_conn
                .clone()
                .or_else(|| config.as_ref().and_then(|c| c.pg_conn.clone()));

            let result = oltp::run(oltp_args);
            if let Some(output_path) = output {
                result.save(Path::new(&output_path)).unwrap();
                println!("Results saved to: {}", output_path);
            } else {
                result.print_json();
            }

            if let Some(ref conn) = pg_conn {
                println!("\n=== PostgreSQL Comparison ===");
                run_pg_comparison(conn, 100);
            }
        }
        Command::Custom(custom_args) => {
            let config = custom_args.config.as_ref().and_then(|p| load_config(p));
            let output = custom_args
                .output
                .clone()
                .or_else(|| config.as_ref().and_then(|c| c.output.clone()));
            let pg_conn = custom_args
                .pg_conn
                .clone()
                .or_else(|| config.as_ref().and_then(|c| c.pg_conn.clone()));

            let result = custom::run(custom_args);
            if let Some(output_path) = output {
                result.save(Path::new(&output_path)).unwrap();
                println!("Results saved to: {}", output_path);
            } else {
                result.print_json();
            }

            if let Some(ref conn) = pg_conn {
                println!("\n=== PostgreSQL Comparison ===");
                run_pg_comparison(conn, 100);
            }
        }
    };
}

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BenchmarkMetrics {
    pub total_time_ms: u64,
    pub iterations: u32,
    pub avg_latency_ms: f64,
    pub p50_ms: f64,
    pub p95_ms: f64,
    pub p99_ms: f64,
    pub min_ms: f64,
    pub max_ms: f64,
    pub qps: f64,
}

impl BenchmarkMetrics {
    pub fn calculate(latencies: &[u64], iterations: u32) -> Self {
        if latencies.is_empty() {
            return Self {
                total_time_ms: 0,
                iterations,
                avg_latency_ms: 0.0,
                p50_ms: 0.0,
                p95_ms: 0.0,
                p99_ms: 0.0,
                min_ms: 0.0,
                max_ms: 0.0,
                qps: 0.0,
            };
        }

        let mut sorted = latencies.to_vec();
        sorted.sort();

        let sum: u64 = sorted.iter().sum();
        let count = sorted.len() as u64;

        Self {
            total_time_ms: sum,
            iterations,
            avg_latency_ms: sum as f64 / count as f64,
            p50_ms: percentile(&sorted, 50) as f64,
            p95_ms: percentile(&sorted, 95) as f64,
            p99_ms: percentile(&sorted, 99) as f64,
            min_ms: sorted.first().copied().unwrap_or(0) as f64,
            max_ms: sorted.last().copied().unwrap_or(0) as f64,
            qps: 1000.0 * count as f64 / sum as f64,
        }
    }
}

fn percentile(sorted: &[u64], p: usize) -> u64 {
    if sorted.is_empty() {
        return 0;
    }
    let idx = (sorted.len() * p / 100).min(sorted.len() - 1);
    sorted[idx]
}

pub struct LatencyCollector {
    samples: Vec<u64>,
}

impl Default for LatencyCollector {
    fn default() -> Self {
        Self::new()
    }
}

impl LatencyCollector {
    pub fn new() -> Self {
        Self {
            samples: Vec::new(),
        }
    }

    pub fn record(&mut self, latency_ns: u64) {
        self.samples.push(latency_ns / 1_000_000);
    }

    pub fn into_metrics(self, iterations: u32) -> BenchmarkMetrics {
        BenchmarkMetrics::calculate(&self.samples, iterations)
    }
}

use serde::{Deserialize, Serialize};
use std::fs::File;
use std::io::Write;
use std::path::Path;

use crate::metrics::BenchmarkMetrics;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BenchmarkResult {
    pub timestamp: String,
    pub version: String,
    pub workload: String,
    pub config: serde_json::Value,
    pub metrics: BenchmarkMetrics,
    pub queries: Vec<QueryResult>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct QueryResult {
    pub name: String,
    pub avg_latency_ms: f64,
    pub min_latency_ms: f64,
    pub max_latency_ms: f64,
    pub iterations: u32,
}

impl BenchmarkResult {
    pub fn new(workload: String, config: serde_json::Value) -> Self {
        Self {
            timestamp: chrono::Utc::now().to_rfc3339(),
            version: env!("CARGO_PKG_VERSION").to_string(),
            workload,
            config,
            metrics: BenchmarkMetrics::calculate(&[], 0),
            queries: Vec::new(),
        }
    }

    pub fn save(&self, path: &Path) -> std::io::Result<()> {
        let json = serde_json::to_string_pretty(self)?;
        let mut file = File::create(path)?;
        file.write_all(json.as_bytes())?;
        Ok(())
    }

    pub fn print_json(&self) {
        println!("{}", serde_json::to_string_pretty(self).unwrap());
    }
}

