        (0..count)
            .map(|_| Value::Integer((self.seed as i64) % (max - min) + min))
            .collect()
    }

    pub fn generate_strings(&mut self, count: usize, prefix: &str) -> Vec<Value> {
        (0..count)
            .map(|i| Value::Text(format!("{}{}", prefix, i)))
