use crossbeam_channel::{bounded, Receiver, Sender};
pub use sqlrustgo_common::connection_pool::PoolConfig;
use sqlrustgo_executor::LocalExecutor;
use sqlrustgo_storage::MemoryStorage;
use std::sync::Arc;

pub struct PooledSession {
    pub executor: LocalExecutor<'static>,
    pub storage: Arc<MemoryStorage>,
    pub transaction_id: Option<u64>,
    in_use: bool,
}

impl std::fmt::Debug for PooledSession {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PooledSession")
            .field("transaction_id", &self.transaction_id)
            .field("in_use", &self.in_use)
            .finish()
    }
}

impl PooledSession {
    pub fn new() -> Self {
        let storage = Arc::new(MemoryStorage::new());
        let storage_ptr = Arc::as_ptr(&storage);
        let executor = LocalExecutor::new(unsafe { &*storage_ptr });
        Self {
            executor,
            storage,
            transaction_id: None,
            in_use: false,
        }
    }

    pub fn is_available(&self) -> bool {
        !self.in_use
    }
}

impl Default for PooledSession {
    fn default() -> Self {
        Self::new()
    }
}

impl Clone for PooledSession {
    fn clone(&self) -> Self {
        let storage = Arc::new(MemoryStorage::new());
        let storage_ptr = Arc::as_ptr(&storage);
        let executor = LocalExecutor::new(unsafe { &*storage_ptr });
        Self {
            executor,
            storage,
            transaction_id: None,
            in_use: false,
        }
    }
}

#[derive(Clone)]
pub struct ConnectionPool {
    #[allow(dead_code)]
    sessions: Arc<Vec<PooledSession>>,
    available: Sender<PooledSession>,
    received: Receiver<PooledSession>,
    config: PoolConfig,
}

impl ConnectionPool {
    pub fn new(config: PoolConfig) -> Self {
        let (available, received) = bounded(config.size);
        let mut sessions = Vec::with_capacity(config.size);

        for _ in 0..config.size {
            let session = PooledSession::new();
            let _ = available.send(session);
            sessions.push(PooledSession::new());
        }

        Self {
            sessions: Arc::new(sessions),
            available,
            received,
            config,
        }
    }

    pub fn acquire(&self) -> PooledConnection {
        let session = self.received.recv().unwrap();
        PooledConnection {
            session,
            pool: self.clone(),
        }
    }

    pub fn size(&self) -> usize {
        self.config.size
    }

    fn release(&self, session: PooledSession) {
        let _ = self.available.send(session);
    }
}

pub struct PooledConnection {
    session: PooledSession,
    pool: ConnectionPool,
}

impl PooledConnection {
    pub fn executor(&self) -> &LocalExecutor<'_> {
        &self.session.executor
    }
}

impl Drop for PooledConnection {
    fn drop(&mut self) {
        self.pool.release(self.session.clone());
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::sync::Arc;
    use std::thread;

    #[test]
    fn test_connection_pool_basic_acquire_release() {
        let config = PoolConfig {
            size: 5,
            timeout_ms: 5000,
        };
        let pool = ConnectionPool::new(config);

        assert_eq!(pool.size(), 5);

        // Acquire and release a connection
        let conn = pool.acquire();
        drop(conn);

        // Should be able to acquire again
        let conn2 = pool.acquire();
        drop(conn2);
    }

    #[test]
    fn test_connection_pool_concurrent_50_connections() {
        let config = PoolConfig {
            size: 50,
            timeout_ms: 5000,
        };
        let pool = ConnectionPool::new(config);
        let pool = Arc::new(pool);

        let success_count = Arc::new(AtomicUsize::new(0));

        let handles: Vec<_> = (0..50)
            .map(|_| {
                let pool = Arc::clone(&pool);
                let success_count = Arc::clone(&success_count);
                thread::spawn(move || {
                    let conn = pool.acquire();
                    // Simulate some work by checking the executor exists
                    let _executor = conn.executor();
                    drop(conn);
                    success_count.fetch_add(1, Ordering::SeqCst);
                })
            })
            .collect();

        for handle in handles {
            handle.join().unwrap();
        }

        assert_eq!(success_count.load(Ordering::SeqCst), 50);
    }

    #[test]
    fn test_connection_pool_concurrent_100_connections() {
        let config = PoolConfig {
            size: 50,
            timeout_ms: 5000,
        };
        let pool = ConnectionPool::new(config);
        let pool = Arc::new(pool);

        let success_count = Arc::new(AtomicUsize::new(0));

        let handles: Vec<_> = (0..100)
            .map(|_| {
                let pool = Arc::clone(&pool);
                let success_count = Arc::clone(&success_count);
                thread::spawn(move || {
                    // Small delay to increase contention
                    thread::sleep(std::time::Duration::from_micros(100));
                    let conn = pool.acquire();
                    let _executor = conn.executor();
                    drop(conn);
                    success_count.fetch_add(1, Ordering::SeqCst);
                })
            })
            .collect();

        for handle in handles {
            handle.join().unwrap();
        }

        // All 100 should complete even with only 50 sessions
        // because connections are released back to the pool
        assert_eq!(success_count.load(Ordering::SeqCst), 100);
    }

    #[test]
    fn test_connection_pool_reuse_sessions() {
        let config = PoolConfig {
            size: 5,
            timeout_ms: 5000,
        };
        let pool = ConnectionPool::new(config);

        let mut conn_handles = vec![];
        // Acquire all 5 connections
        for _ in 0..5 {
            let conn = pool.acquire();
            conn_handles.push(conn);
        }

        // Release all
        conn_handles.clear();

        // Should be able to acquire all again
        for _ in 0..5 {
            let conn = pool.acquire();
            drop(conn);
        }
    }

    #[test]
    fn test_pooled_session_clone_creates_fresh_session() {
        let session1 = PooledSession::new();
        let session2 = session1.clone();

        // Cloned sessions should be independent
        assert!(session1.is_available());
        assert!(session2.is_available());
    }
}

//! Health Check Module
//!
//! Provides health check endpoints for Kubernetes liveness and readiness probes.
//!
//! # Usage
//!
//! ```ignore
//! use sqlrustgo_server::health::{HealthChecker, HealthStatus};
//!
//! let checker = HealthChecker::new("1.3.0");
//! let live_status = checker.check_live();
//! let ready_report = checker.check_ready();
//! ```

use serde::{Deserialize, Serialize};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum HealthStatus {
    Healthy,
    Degraded,
    Unhealthy,
}

impl HealthStatus {
    pub fn as_str(&self) -> &'static str {
        match self {
            HealthStatus::Healthy => "healthy",
            HealthStatus::Degraded => "degraded",
            HealthStatus::Unhealthy => "unhealthy",
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ComponentHealth {
    pub name: String,
    pub status: HealthStatus,
    pub message: Option<String>,
    pub latency_ms: Option<u64>,
}

impl ComponentHealth {
    pub fn new(name: impl Into<String>, status: HealthStatus) -> Self {
        Self {
            name: name.into(),
            status,
            message: None,
            latency_ms: None,
        }
    }

    pub fn with_message(mut self, message: impl Into<String>) -> Self {
        self.message = Some(message.into());
        self
    }

    pub fn with_latency(mut self, latency_ms: u64) -> Self {
        self.latency_ms = Some(latency_ms);
        self
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ComprehensiveHealthReport {
    pub status: HealthStatus,
    pub version: String,
    pub timestamp: u64,
    pub uptime_seconds: u64,
    pub components: std::collections::HashMap<String, ComponentHealth>,
    pub metrics: Option<HealthMetrics>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HealthMetrics {
    pub queries_total: u64,
    pub queries_failed: u64,
    pub avg_query_ms: f64,
}

impl ComprehensiveHealthReport {
    pub fn new(
        status: HealthStatus,
        version: String,
        uptime_seconds: u64,
        components: std::collections::HashMap<String, ComponentHealth>,
        metrics: Option<HealthMetrics>,
    ) -> Self {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_millis() as u64)
            .unwrap_or(0);

        Self {
            status,
            version,
            timestamp,
            uptime_seconds,
            components,
            metrics,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HealthReport {
    pub status: HealthStatus,
    pub version: String,
    pub timestamp: u64,
    pub components: Vec<ComponentHealth>,
}

impl HealthReport {
    pub fn new(version: impl Into<String>, components: Vec<ComponentHealth>) -> Self {
        let status = if components.iter().all(|c| c.status == HealthStatus::Healthy) {
            HealthStatus::Healthy
        } else if components
            .iter()
            .any(|c| c.status == HealthStatus::Unhealthy)
        {
            HealthStatus::Unhealthy
        } else {
            HealthStatus::Degraded
        };

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_millis() as u64)
            .unwrap_or(0);

        Self {
            status,
            version: version.into(),
            timestamp,
            components,
        }
    }
}

pub trait HealthComponent: Send + Sync {
    fn name(&self) -> &str;
    fn check(&self) -> ComponentHealth;
}

pub struct HealthChecker {
    version: String,
    start_time: SystemTime,
    components: Vec<Box<dyn HealthComponent>>,
}

impl HealthChecker {
    pub fn new(version: impl Into<String>) -> Self {
        Self {
            version: version.into(),
            start_time: SystemTime::now(),
            components: Vec::new(),
        }
    }

    pub fn with_component<C: HealthComponent + 'static>(mut self, component: C) -> Self {
        self.components.push(Box::new(component));
        self
    }

    pub fn check_live(&self) -> HealthStatus {
        HealthStatus::Healthy
    }

    pub fn check_ready(&self) -> HealthReport {
        let components: Vec<ComponentHealth> = self.components.iter().map(|c| c.check()).collect();

        HealthReport::new(&self.version, components)
    }

    pub fn version(&self) -> &str {
        &self.version
    }

    pub fn uptime_seconds(&self) -> u64 {
        self.start_time.elapsed().map(|d| d.as_secs()).unwrap_or(0)
    }

    pub fn check_health(&self) -> ComprehensiveHealthReport {
        let components: Vec<ComponentHealth> = self.components.iter().map(|c| c.check()).collect();

        let overall_status = if components.iter().all(|c| c.status == HealthStatus::Healthy) {
            HealthStatus::Healthy
        } else if components
            .iter()
            .any(|c| c.status == HealthStatus::Unhealthy)
        {
            HealthStatus::Unhealthy
        } else {
            HealthStatus::Degraded
        };

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_millis() as u64)
            .unwrap_or(0);

        ComprehensiveHealthReport {
            status: overall_status,
            version: self.version.clone(),
            timestamp,
            uptime_seconds: self.uptime_seconds(),
            components: components
                .into_iter()
                .map(|c| (c.name.clone(), c))
                .collect(),
            metrics: None,
        }
    }
}

impl Default for HealthChecker {
    fn default() -> Self {
        Self::new("unknown")
    }
}

#[derive(Debug, Clone, Default)]
pub struct SystemHealthComponent;

impl SystemHealthComponent {
    pub fn new() -> Self {
