    }
}

impl HealthComponent for SystemHealthComponent {
    fn name(&self) -> &str {
        "system"
    }

    fn check(&self) -> ComponentHealth {
        ComponentHealth::new("system", HealthStatus::Healthy).with_message("System is operational")
    }
}

