        use crate::mvcc::TxId;

        let mut manager = TransactionManager::new();
        manager.set_isolation_level(IsolationLevel::ReadCommitted);

        let _tx1 = manager.begin().unwrap();
        let ctx = manager.get_transaction_context_for_query().unwrap();

        assert!(!ctx.is_visible(TxId::new(999), None));

        manager.rollback().unwrap();
    }

    #[test]
    fn test_snapshot_refresh_on_each_query() {
        let mut manager = TransactionManager::new();
        manager.set_isolation_level(IsolationLevel::ReadCommitted);

        let _tx_id = manager.begin().unwrap();

        let ctx1 = manager.get_transaction_context_for_query().unwrap();
        let ts1 = ctx1.snapshot.snapshot_timestamp;

        let _ = manager.get_global_timestamp().unwrap();

        let ctx2 = manager.get_transaction_context_for_query().unwrap();
        let ts2 = ctx2.snapshot.snapshot_timestamp;

        assert!(ts2 >= ts1);

        manager.commit().unwrap();
    }
}

//! MVCC (Multi-Version Concurrency Control) implementation
//!
//! This module provides snapshot isolation, version chain management,
//! and visibility checking for concurrent transaction support.

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

pub const INVALID_TX_ID: u64 = 0;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct TxId(u64);

impl TxId {
    pub fn new(id: u64) -> Self {
        Self(id)
    }

    pub fn invalid() -> Self {
        Self(INVALID_TX_ID)
    }

    pub fn is_valid(&self) -> bool {
        self.0 != INVALID_TX_ID
    }

    pub fn as_u64(&self) -> u64 {
        self.0
    }
}

impl Default for TxId {
    fn default() -> Self {
        Self::invalid()
    }
}

impl std::fmt::Display for TxId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.0)
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum TransactionStatus {
    Active,
    Committed,
    Aborted,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Transaction {
    pub id: TxId,
    pub status: TransactionStatus,
    pub start_timestamp: u64,
    pub commit_timestamp: Option<u64>,
}

impl Transaction {
    pub fn new(id: TxId, start_timestamp: u64) -> Self {
        Self {
            id,
            status: TransactionStatus::Active,
            start_timestamp,
            commit_timestamp: None,
        }
    }

    pub fn commit(&mut self, commit_timestamp: u64) {
        self.status = TransactionStatus::Committed;
        self.commit_timestamp = Some(commit_timestamp);
    }

    pub fn abort(&mut self) {
        self.status = TransactionStatus::Aborted;
    }

    pub fn is_active(&self) -> bool {
        self.status == TransactionStatus::Active
    }

    pub fn is_committed(&self) -> bool {
        self.status == TransactionStatus::Committed
    }

    pub fn is_aborted(&self) -> bool {
        self.status == TransactionStatus::Aborted
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct Snapshot {
    pub tx_id: TxId,
    pub snapshot_timestamp: u64,
    pub active_transactions: Vec<TxId>,
}

impl Snapshot {
    pub fn new(tx_id: TxId, snapshot_timestamp: u64, active: Vec<TxId>) -> Self {
        Self {
            tx_id,
            snapshot_timestamp,
            active_transactions: active,
        }
    }

    pub fn new_read_committed(tx_id: TxId, snapshot_timestamp: u64) -> Self {
        Self {
            tx_id,
            snapshot_timestamp,
            active_transactions: Vec::new(),
        }
    }

    pub fn is_visible(&self, tx_id: TxId, commit_timestamp: Option<u64>) -> bool {
        if tx_id == self.tx_id {
            return true;
        }

        for active in &self.active_transactions {
            if *active == tx_id {
                return false;
            }
        }

        match commit_timestamp {
            Some(ts) => ts < self.snapshot_timestamp,
            None => false,
        }
    }

    pub fn is_visible_read_committed(
        &self,
        tx_id: TxId,
        commit_timestamp: Option<u64>,
        current_timestamp: u64,
    ) -> bool {
        if tx_id == self.tx_id {
            return true;
        }

        match commit_timestamp {
            Some(ts) => ts < current_timestamp,
            None => false,
        }
    }

    pub fn refresh_for_read_committed(&mut self, current_timestamp: u64) {
        self.snapshot_timestamp = current_timestamp;
        self.active_transactions.clear();
    }
}

